int sum(vector<int> &numbers)
{
    int total = 0; // ONE extra variable, regardless of numbers' size
    for (int i = 0; i < numbers.size(); i++)
    {
        total += numbers[i];
    }
    return total;
}

vector<int> doubleAll(vector<int> &numbers)
{
    vector<int> result; // grows to match numbers' size
    for (int n : numbers)
    {
        result.push_back(n * 2);
    }
    return result;
}

int factorial(int n)
{
    if (n == 0) return 1;
    return n * factorial(n - 1);
}

// Using unordered_map (O(n) extra space) to check for duplicates in O(n) time
unordered_map<int, bool> seen;
for (int n : numbers)
{
    if (seen[n]) { /* duplicate found */ }
    seen[n] = true;
}

